
:deep(.modal-wrapper .modal-container) {
	height: 700px;
}

:deep(.modal-wrapper .dialog__content) {
	width: 100%;
	height: 100%;
	display: flex;
	flex-direction: column;
}

.selector {
	&__heading {
		margin-bottom: 4px;
	}

	&__subtitle {
		color: var(--color-text-maxcontrast);
		margin-bottom: 8px;
	}

	&__search {
		margin-bottom: 10px;
	}

	&__list {
		height: 100%;
	}

	&__action {
		flex-shrink: 0;
		margin-inline-start: auto;
	}
}
